def HSS(points, k: int, reference_point) -> np.ndarray:
    n, m = points.shape

    if k <= 0 or k > n:
        raise ValueError("k must be greater than 0 and not larger than the number of points.")

    # 创建索引列表
    R_indices = list(range(n))
    R_objectives_array = points
    random.shuffle(R_indices)

    # 1. GSI算法 - 初始化
    S = set(R_indices[:k])
    elements_to_insert = R_indices[k:]

    # 2. GSI算法 - 迭代过程
    for element_to_add in elements_to_insert:
        S.add(element_to_add)

        worst_element_index = None
        min_contribution = float('inf')

        # 获取当前 S 的超体积
        if not S:
            M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
            current_selected = np.empty((0, M))
        else:
            current_selected = R_objectives_array[list(S)]

        if current_selected.size == 0:
            current_hv = 0.0
        else:
            try:
                hv = pg.hypervolume(current_selected)
                current_hv = hv.compute(reference_point)
            except Exception as e:
                print(f"Hypervolume calculation error: {e}")
                current_hv = 0.0

        for s_index in list(S):
            # 尝试移除 s_index: S_temp = S - {s_index}
            S_temp = S - {s_index}

            # 移除后的超体积
            if not S_temp:
                M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
                temp_selected = np.empty((0, M))
            else:
                temp_selected = R_objectives_array[list(S_temp)]

            if temp_selected.size == 0:
                hv_after_remove = 0.0
            else:
                try:
                    hv = pg.hypervolume(temp_selected)
                    hv_after_remove = hv.compute(reference_point)
                except Exception as e:
                    print(f"Hypervolume calculation error: {e}")
                    hv_after_remove = 0.0

            # 贡献度 = 移除前的 HV - 移除后的 HV
            contribution = current_hv - hv_after_remove

            if contribution < min_contribution:
                min_contribution = contribution
                worst_element_index = s_index

        if worst_element_index is not None:
            S.remove(worst_element_index)

    # 3. LS算法 - 初始化
    current_S = set(S)
    R_set = set(R_indices)

    if len(current_S) != k:
        raise ValueError("初始子集 S 的大小必须等于 k。")

    # 4. LS算法 - 迭代过程
    while True:
        # 获取当前 S 的超体积
        if not current_S:
            M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
            current_selected = np.empty((0, M))
        else:
            current_selected = R_objectives_array[list(current_S)]

        if current_selected.size == 0:
            current_hv = 0.0
        else:
            try:
                hv = pg.hypervolume(current_selected)
                current_hv = hv.compute(reference_point)
            except Exception as e:
                print(f"Hypervolume calculation error: {e}")
                current_hv = 0.0

        found_improvement = False

        R_minus_S = list(R_set - current_S)
        S_list = list(current_S)

        # 遍历所有可能的交换对 (s, r)
        for s_index in S_list:
            for r_index in R_minus_S:
                # 尝试交换: S' = S - {s_index} + {r_index}
                S_new = (current_S - {s_index}) | {r_index}

                # 计算新集合 S_new 的超体积
                if not S_new:
                    M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
                    new_selected = np.empty((0, M))
                else:
                    new_selected = R_objectives_array[list(S_new)]

                if new_selected.size == 0:
                    new_hv = 0.0
                else:
                    try:
                        hv = pg.hypervolume(new_selected)
                        new_hv = hv.compute(reference_point)
                    except Exception as e:
                        print(f"Hypervolume calculation error: {e}")
                        new_hv = 0.0

                # 检查是否是改进
                if new_hv > current_hv:
                    current_S = S_new
                    found_improvement = True
                    break  # 跳出 r_index 循环

            if found_improvement:
                break  # 跳出 s_index 循环

        if not found_improvement:
            break

    # 5. 返回选择的点
    if not current_S:
        M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
        selected_points = np.empty((0, M))
    else:
        selected_points = R_objectives_array[list(current_S)]

    return selected_points

def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1
    if k == 0:
        return np.empty((0, points.shape[1]))
    if k >= len(points):
        return points.copy()

    D = points.shape[1]
    remaining_indices = list(range(len(points)))
    selected_indices = []

    def hypervolume_contribution(candidates_idx, current_set_idx):
        if not current_set_idx:
            return np.prod(reference_point - points[candidates_idx], axis=1)

        current_points = points[current_set_idx]
        contributions = np.zeros(len(candidates_idx))
        for i, idx in enumerate(candidates_idx):
            point = points[idx]
            dominated = np.all(current_points <= point, axis=1)
            if np.any(dominated):
                contributions[i] = 0.0
                continue

            non_dominated = current_points[~dominated]
            if len(non_dominated) == 0:
                contributions[i] = np.prod(reference_point - point)
                continue

            def split_volume(point, ref, others, dim):
                if dim == D:
                    return np.prod(ref - point)
                others = others[others[:, dim] < ref[dim]]
                if len(others) == 0:
                    return np.prod(ref - point)
                next_ref = ref.copy()
                next_ref[dim] = np.min(others[:, dim])
                if point[dim] >= next_ref[dim]:
                    return 0.0
                vol_before = split_volume(point, next_ref, others, dim + 1)
                other_ref = ref.copy()
                other_ref[dim] = next_ref[dim]
                vol_after = split_volume(point, other_ref, others, dim)
                return vol_before + vol_after

            contributions[i] = split_volume(point, reference_point, non_dominated, 0)
        return contributions

    while len(selected_indices) < k:
        contribs = hypervolume_contribution(remaining_indices, selected_indices)
        best_idx = np.argmax(contribs)
        selected_indices.append(remaining_indices.pop(best_idx))

    return points[selected_indices]
